proof fn phi_1_fold_left_push_empty()
    ensures
        Seq::<int>::empty().push(42).fold_left(0int, |acc: int, x: int| acc + x) == 42,
{
    lemma_fold_left_push(Seq::<int>::empty(), 42, 0int, |acc: int, x: int| acc + x);
}

proof fn phi_2_fold_left_push_non_commutative()
    ensures
        seq![1int, 2].push(3).fold_left(0int, |acc: int, x: int| acc - x) == ((0 - 1) - 2) - 3,
{
    lemma_fold_left_push(seq![1int, 2], 3, 0int, |acc: int, x: int| acc - x);
}

proof fn phi_3_fold_left_push_ignores_order(a: int, b: int)
    requires
        a != b,
    ensures
        seq![a].push(b).fold_left(0int, |acc: int, x: int| acc - x)
            != seq![b].push(a).fold_left(0int, |acc: int, x: int| acc - x),
{
    lemma_fold_left_push(seq![a], b, 0int, |acc: int, x: int| acc - x);
    lemma_fold_left_push(seq![b], a, 0int, |acc: int, x: int| acc - x);
}

proof fn phi_4_fold_left_push_concat_equivalence(s: Seq<int>, a: int, b: int)
    ensures
        s.push(a).push(b).fold_left(0int, |acc: int, x: int| acc + x)
            == s.fold_left(0int, |acc: int, x: int| acc + x) + a + b,
{
    lemma_fold_left_push(s.push(a), b, 0int, |acc: int, x: int| acc + x);
    lemma_fold_left_push(s, a, 0int, |acc: int, x: int| acc + x);
}

proof fn phi_5_fold_left_push_closure_mismatch()
    ensures
        seq![1int].push(2).fold_left(10int, |acc: int, x: int| x)
            == (|acc: int, x: int| x)(seq![1int].fold_left(10int, |acc: int, x: int| x), 2),
{
    lemma_fold_left_push(seq![1int], 2, 10int, |acc: int, x: int| x);
}
